public class DigitSum {
    public static void main(String[] args) {
        int original = 9876;
        int number = original;
        int sum = 0;

        while (number > 0) {
            int lastDigit = number % 10;
            sum += lastDigit;
            number /= 10;
        }

        System.out.println("Number: " + original);
        System.out.println("Sum of digits: " + sum);
    }
}

public class PrimeCheck {
    public static void main(String[] args) {
        int number = 29;
        boolean isPrime;

        if (number <= 1) {
            isPrime = false;
        } else {
            isPrime = true;  // Assume prime until we find a divisor
            for (int i = 2; i < number; i++) {
                if (number % i == 0) {
                    isPrime = false;
                    break;
                }
            }
        }

        System.out.println(number + " is prime: " + isPrime);
    }
}

public class Fibonacci {
    public static void main(String[] args) {
        int count = 10;
        long a = 0;
        long b = 1;

        System.out.print("Fibonacci (first " + count + "): ");

        for (int i = 0; i < count; i++) {
            // Print current
            if (i > 0) {
                System.out.print(", ");
            }
            System.out.print(a);

            // Calculate next
            long next = a + b;
            a = b;
            b = next;
        }

        System.out.println();
    }
}
